INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (0, 8, 0, 6006, 0.3, 129811, "あたしも教官の仕事を\n頑張れば、あいつに\n喜んでもらえたり\nするのかな…", 11, 6, 0, 1);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES ("", "", "", 6007, "", 0, "", 91, 6, "", "");
