INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES ("", 0, "", 6010, "", "vo_minigame_1013", "vo_minigame_1013_top_talk_6_001", 21, 6, "", 0);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (0, 6, 0, 6011, 0.8, 129911, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 11, 6, 0, 1);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES ("", "", "", 6012, "", 0, "", 91, 6, "", "");
