INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (0.2, 0, "", 6014, "", 129811, "drama_talk_surprise_in_shy", 3, 6, 1, "drama_talk_surprise_loop_shy");
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES ("", 0, "", 6015, "", "vo_minigame_1013", "vo_minigame_1013_top_talk_6_002", 21, 6, "", 0);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (0, 9, 0, 6016, 0.3, 129811, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 11, 6, 0, 1);
