INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (0, 6, 0, 7006, 0.3, 129911, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 11, 7, 0, 1);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES ("", "", "", 7007, "", 0, "", 91, 7, "", "");
